public class ArrayOperations {

    private int[] data;
    private int size;

    public ArrayOperations(int capacity) {
        data = new int[capacity];
        size = 0;
    }

    public void fill(int[] values) {
        for (int v : values) data[size++] = v;
    }

    // Insert value at position pos, shifting right
    public int insert(int pos, int value) {
        if (size >= data.length || pos < 0 || pos > size) return size;
        // TODO: shift elements right from size-1 down to pos, then set data[pos]=value, size++
        return size;
    }

    // Delete first occurrence of value, shifting left; return -1 if not found
    public int delete(int value) {
        // TODO: find index of value, shift elements left, size--, return new size; -1 if not found
        return -1;
    }

    public void print() {
        java.util.StringJoiner sj = new java.util.StringJoiner(", ", "[", "]");
        for (int i = 0; i < size; i++) sj.add(String.valueOf(data[i]));
        System.out.println(sj);
    }

    public static void main(String[] args) {
        ArrayOperations ao = new ArrayOperations(10);
        ao.fill(new int[]{1, 2, 3, 4, 5});
        ao.print();
        ao.insert(2, 99);
        ao.print();
        ao.delete(99);
        ao.print();
        System.out.println("Delete 999: " + ao.delete(999));
    }
}

