public class TraversalPatterns {

    public int[] forward(int[] arr) {
        // Return elements in order arr[0], arr[1], ..., arr[n-1]
        int[] result = new int[arr.length];
        for (int i = 0; i < arr.length; i++) result[i] = arr[i];
        return result;
    }

    public int[] backward(int[] arr) {
        // TODO: return elements in reverse order arr[n-1], ..., arr[0]
        return new int[0];
    }

    public int[] alternating(int[] arr) {
        // TODO: visit arr[0], arr[n-1], arr[1], arr[n-2], ...
        // Use two pointers left=0, right=n-1 moving inward
        return new int[0];
    }

    private String arrayToStr(int[] arr) {
        StringBuilder sb = new StringBuilder("[");
        for (int i = 0; i < arr.length; i++) {
            if (i > 0) sb.append(", ");
            sb.append(arr[i]);
        }
        return sb.append("]").toString();
    }

    public static void main(String[] args) {
        TraversalPatterns tp = new TraversalPatterns();
        int[] arr = {1, 2, 3, 4, 5};
        System.out.println("Forward:     " + tp.arrayToStr(tp.forward(arr)));
        System.out.println("Backward:    " + tp.arrayToStr(tp.backward(arr)));
        System.out.println("Alternating: " + tp.arrayToStr(tp.alternating(arr)));
    }
}
